import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, Router } from '@angular/router';
import { NavbarComponent } from '../../components/navbar/navbar.component';
import { ReviewCardComponent } from '../../components/review-card/review-card.component';
import { AuthService } from '../../services/auth.service';
import { UserProfile, UserService } from '../../services/user.service';
import { FriendshipService } from '../../services/friendship.service';

@Component({
  selector: 'app-profile',
  standalone: true,
  imports: [CommonModule, NavbarComponent, ReviewCardComponent],
  templateUrl: './profile.component.html',
  styleUrl: './profile.component.css'
})
export class ProfileComponent implements OnInit {
  userProfile: UserProfile | null = null;
  loading = true;
  error: string | null = null;
  userId: string = '';
  isOwnProfile = false;
  friendRequestSent = false;
  sendingRequest = false;

  constructor(
    private route: ActivatedRoute,
    private router: Router,
    private userService: UserService,
    private authService: AuthService,
    private friendshipService: FriendshipService
  ) {}

  ngOnInit() {
    this.route.paramMap.subscribe(params => {
      this.userId = params.get('userId') || '';
      this.isOwnProfile = this.userId === this.authService.getUserId();
      if (this.userId) {
        this.loadProfile();
      }
    });
  }

  loadProfile() {
    this.loading = true;
    this.error = null;

    this.userService.getUserProfile(this.userId).subscribe({
      next: (profile) => {
        this.userProfile = profile;
        this.loading = false;
      },
      error: () => {
        this.error = 'Failed to load profile';
        this.loading = false;
      }
    });
  }

  sendFriendRequest() {
    if (this.isOwnProfile || this.sendingRequest) return;

    this.sendingRequest = true;
    this.friendshipService.sendFriendRequest(this.userId).subscribe({
      next: () => {
        this.friendRequestSent = true;
        this.sendingRequest = false;
      },
      error: (err) => {
        this.error = err.error?.message || 'Failed to send friend request';
        this.sendingRequest = false;
      }
    });
  }

  goToWatchlist() {
    if (this.isOwnProfile) {
      this.router.navigate(['/watchlist']);
    }
  }

  goBack() {
    this.router.navigate(['/feed']);
  }
}
<div class="profile-container">
  <app-navbar></app-navbar>

  <button class="back-btn" (click)="goBack()">← Back</button>

  <div *ngIf="loading" class="loading">Loading profile...</div>

  <div *ngIf="error" class="error-message">{{ error }}</div>

  <div *ngIf="!loading && userProfile" class="profile-content">
    <div class="profile-header">
      <div class="profile-avatar">
        {{ userProfile.fullName.charAt(0).toUpperCase() }}
      </div>
      <div class="profile-info">
        <h1>{{ userProfile.fullName }}</h1>
        <p class="email" *ngIf="isOwnProfile">{{ userProfile.email }}</p>
        <button
          *ngIf="!isOwnProfile && !friendRequestSent"
          class="btn btn-primary"
          (click)="sendFriendRequest()"
          [disabled]="sendingRequest"
        >
          {{ sendingRequest ? 'Sending...' : '👥 Add Friend' }}
        </button>
        <span *ngIf="!isOwnProfile && friendRequestSent" class="request-sent">
          Friend request sent!
        </span>
      </div>
    </div>

    <div class="profile-stats">
      <div class="stat">
        <span class="stat-number">{{ userProfile.reviewCount }}</span>
        <span class="stat-label">Reviews</span>
      </div>
      <div class="stat">
        <span class="stat-number">{{ userProfile.watchlistCount }}</span>
        <span class="stat-label">Watchlist</span>
      </div>
    </div>

    <div class="recent-reviews">
      <h2>Recent Reviews</h2>
      <div *ngIf="userProfile.recentReviews.length === 0" class="empty">
        No reviews yet
      </div>
      <div *ngIf="userProfile.recentReviews.length > 0" class="reviews-list">
        <app-review-card
          *ngFor="let review of userProfile.recentReviews"
          [review]="review"
        ></app-review-card>
      </div>
    </div>
  </div>
</div>
